#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        long long free = N / 5;
        long long cost = N - free;
        printf("%lld\n", cost);
    }
    return 0;
}

